(self.webpackChunk=self.webpackChunk||[]).push([[177],{1268:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>e});const e={key:"v-af8d10f4",path:"/java/java-connect.html",title:"JAVA连接常用软件",lang:"en-US",frontmatter:{title:"JAVA连接常用软件"},excerpt:"",headers:[{level:2,title:"FastDFS",slug:"fastdfs",children:[{level:3,title:"安装 FastDFS Java 客户端",slug:"安装-fastdfs-java-客户端",children:[]},{level:3,title:"在项目中添加依赖",slug:"在项目中添加依赖",children:[]},{level:3,title:"创建 FastDFS 工具类",slug:"创建-fastdfs-工具类",children:[]}]}],filePathRelative:"java/java-connect.md",git:{updatedTime:1626154667e3,contributors:[]}}},9426:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>r});const e=(0,a(6252).uE)('<h2 id="fastdfs" tabindex="-1"><a class="header-anchor" href="#fastdfs" aria-hidden="true">#</a> FastDFS</h2><h3 id="安装-fastdfs-java-客户端" tabindex="-1"><a class="header-anchor" href="#安装-fastdfs-java-客户端" aria-hidden="true">#</a> 安装 FastDFS Java 客户端</h3><blockquote><p>从 GitHub 克隆源码</p></blockquote><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> clone https://github.com/happyfish100/fastdfs-client-java.git\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><blockquote><p>从源码安装并部署到 Nexus 部署前别忘记在 pom.xml 中增加 Nexus 相关配置，配置代码如下：</p></blockquote><div class="language-xml ext-xml line-numbers-mode"><pre class="language-xml"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>distributionManagement</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>repository</span><span class="token punctuation">&gt;</span></span>\n        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>id</span><span class="token punctuation">&gt;</span></span>nexus-releases<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>id</span><span class="token punctuation">&gt;</span></span>\n        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>name</span><span class="token punctuation">&gt;</span></span>Nexus Release Repository<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>name</span><span class="token punctuation">&gt;</span></span>\n        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>url</span><span class="token punctuation">&gt;</span></span>http://192.168.75.128:8081/repository/maven-releases/<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>url</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>repository</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>snapshotRepository</span><span class="token punctuation">&gt;</span></span>\n        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>id</span><span class="token punctuation">&gt;</span></span>nexus-snapshots<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>id</span><span class="token punctuation">&gt;</span></span>\n        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>name</span><span class="token punctuation">&gt;</span></span>Nexus Snapshot Repository<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>name</span><span class="token punctuation">&gt;</span></span>\n        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>url</span><span class="token punctuation">&gt;</span></span>http://192.168.75.128:8081/repository/maven-snapshots/<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>url</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>snapshotRepository</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>distributionManagement</span><span class="token punctuation">&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>mvn clean <span class="token function">install</span> deploy\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="在项目中添加依赖" tabindex="-1"><a class="header-anchor" href="#在项目中添加依赖" aria-hidden="true">#</a> 在项目中添加依赖</h3><div class="language-xml ext-xml line-numbers-mode"><pre class="language-xml"><code><span class="token comment">&lt;!-- FastDFS Begin --&gt;</span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependency</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>org.csource<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>fastdfs-client-java<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>version</span><span class="token punctuation">&gt;</span></span>1.27-SNAPSHOT<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>version</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependency</span><span class="token punctuation">&gt;</span></span>\n<span class="token comment">&lt;!-- FastDFS End --&gt;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="创建-fastdfs-工具类" tabindex="-1"><a class="header-anchor" href="#创建-fastdfs-工具类" aria-hidden="true">#</a> 创建 FastDFS 工具类</h3><blockquote><p>定义文件存储服务接口</p></blockquote><div class="language-java ext-java line-numbers-mode"><pre class="language-java"><code><span class="token doc-comment comment">/**\n * 文件存储服务接口\n * <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span>Title: StorageService<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>\n * <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span>Description: <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>\n *\n * <span class="token keyword">@author</span> Lusifer\n * <span class="token keyword">@version</span> 1.0.0\n * <span class="token keyword">@date</span> 2018/8/14 5:22\n */</span>\n<span class="token keyword">public</span> <span class="token keyword">interface</span> <span class="token class-name">StorageService</span> <span class="token punctuation">{</span>\n    <span class="token doc-comment comment">/**\n     * 上传文件\n     *\n     * <span class="token keyword">@param</span> <span class="token parameter">data</span>    文件的二进制内容\n     * <span class="token keyword">@param</span> <span class="token parameter">extName</span> 扩展名\n     * <span class="token keyword">@return</span> 上传成功后返回生成的文件id；失败，返回null\n     */</span>\n    <span class="token keyword">public</span> <span class="token class-name">String</span> <span class="token function">upload</span><span class="token punctuation">(</span><span class="token keyword">byte</span><span class="token punctuation">[</span><span class="token punctuation">]</span> data<span class="token punctuation">,</span> <span class="token class-name">String</span> extName<span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n    <span class="token doc-comment comment">/**\n     * 删除文件\n     *\n     * <span class="token keyword">@param</span> <span class="token parameter">fileId</span> 被删除的文件id\n     * <span class="token keyword">@return</span> 删除成功后返回0，失败后返回错误代码\n     */</span>\n    <span class="token keyword">public</span> <span class="token keyword">int</span> <span class="token function">delete</span><span class="token punctuation">(</span><span class="token class-name">String</span> fileId<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br></div></div><blockquote><p>实现文件存储服务接口</p></blockquote><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>import org.csource.common.NameValuePair;\nimport org.csource.fastdfs.ClientGlobal;\nimport org.csource.fastdfs.StorageClient1;\nimport org.csource.fastdfs.StorageServer;\nimport org.csource.fastdfs.TrackerClient;\nimport org.csource.fastdfs.TrackerGroup;\nimport org.csource.fastdfs.TrackerServer;\nimport org.slf4j.Logger;\nimport org.slf4j.LoggerFactory;\nimport org.springframework.beans.factory.InitializingBean;\nimport org.springframework.beans.factory.annotation.Value;\n\nimport java.io.File;\nimport java.io.FileWriter;\nimport java.io.IOException;\nimport java.io.PrintWriter;\n\n/**\n * 文件存储服务实现\n * &lt;p&gt;Title: FastDFSStorageService&lt;/p&gt;\n * &lt;p&gt;Description: &lt;/p&gt;\n *\n * @author Lusifer\n * @version 1.0.0\n * @date 2018/8/14 5:27\n */\npublic class FastDFSStorageService implements StorageService, InitializingBean {\n    private static final Logger logger = LoggerFactory.getLogger(FastDFSStorageService.class);\n\n    private TrackerClient trackerClient;\n\n    @Value(&quot;${storage.fastdfs.tracker_server}&quot;)\n    private String trackerServer;\n\n    @Override\n    public String upload(byte[] data, String extName) {\n        TrackerServer trackerServer = null;\n        StorageServer storageServer = null;\n        StorageClient1 storageClient1 = null;\n        try {\n            NameValuePair[] meta_list = null; // new NameValuePair[0];\n\n            trackerServer = trackerClient.getConnection();\n            if (trackerServer == null) {\n                logger.error(&quot;getConnection return null&quot;);\n            }\n            storageServer = trackerClient.getStoreStorage(trackerServer);\n            storageClient1 = new StorageClient1(trackerServer, storageServer);\n            String fileid = storageClient1.upload_file1(data, extName, meta_list);\n            logger.debug(&quot;uploaded file &lt;{}&gt;&quot;, fileid);\n            return fileid;\n        } catch (Exception ex) {\n            logger.error(&quot;Upload fail&quot;, ex);\n            return null;\n        } finally {\n            if (storageServer != null) {\n                try {\n                    storageServer.close();\n                } catch (IOException e) {\n                    e.printStackTrace();\n                }\n            }\n            if (trackerServer != null) {\n                try {\n                    trackerServer.close();\n                } catch (IOException e) {\n                    e.printStackTrace();\n                }\n            }\n            storageClient1 = null;\n        }\n    }\n\n    @Override\n    public int delete(String fileId) {\n//        System.out.println(&quot;deleting ....&quot;);\n        TrackerServer trackerServer = null;\n        StorageServer storageServer = null;\n        StorageClient1 storageClient1 = null;\n        int index = fileId.indexOf(&#39;/&#39;);\n        String groupName = fileId.substring(0, index);\n        try {\n            trackerServer = trackerClient.getConnection();\n            if (trackerServer == null) {\n                logger.error(&quot;getConnection return null&quot;);\n            }\n            storageServer = trackerClient.getStoreStorage(trackerServer, groupName);\n            storageClient1 = new StorageClient1(trackerServer, storageServer);\n            int result = storageClient1.delete_file1(fileId);\n            return result;\n        } catch (Exception ex) {\n            logger.error(&quot;Delete fail&quot;, ex);\n            return 1;\n        } finally {\n            if (storageServer != null) {\n                try {\n                    storageServer.close();\n                } catch (IOException e) {\n                    e.printStackTrace();\n                }\n            }\n            if (trackerServer != null) {\n                try {\n                    trackerServer.close();\n                } catch (IOException e) {\n                    e.printStackTrace();\n                }\n            }\n            storageClient1 = null;\n        }\n    }\n\n    @Override\n    public void afterPropertiesSet() throws Exception {\n        File confFile = File.createTempFile(&quot;fastdfs&quot;, &quot;.conf&quot;);\n        PrintWriter confWriter = new PrintWriter(new FileWriter(confFile));\n        confWriter.println(&quot;tracker_server=&quot; + trackerServer);\n        confWriter.close();\n        ClientGlobal.init(confFile.getAbsolutePath());\n        confFile.delete();\n        TrackerGroup trackerGroup = ClientGlobal.g_tracker_group;\n        trackerClient = new TrackerClient(trackerGroup);\n\n        logger.info(&quot;Init FastDFS with tracker_server : {}&quot;, trackerServer);\n    }\n}\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br><span class="line-number">47</span><br><span class="line-number">48</span><br><span class="line-number">49</span><br><span class="line-number">50</span><br><span class="line-number">51</span><br><span class="line-number">52</span><br><span class="line-number">53</span><br><span class="line-number">54</span><br><span class="line-number">55</span><br><span class="line-number">56</span><br><span class="line-number">57</span><br><span class="line-number">58</span><br><span class="line-number">59</span><br><span class="line-number">60</span><br><span class="line-number">61</span><br><span class="line-number">62</span><br><span class="line-number">63</span><br><span class="line-number">64</span><br><span class="line-number">65</span><br><span class="line-number">66</span><br><span class="line-number">67</span><br><span class="line-number">68</span><br><span class="line-number">69</span><br><span class="line-number">70</span><br><span class="line-number">71</span><br><span class="line-number">72</span><br><span class="line-number">73</span><br><span class="line-number">74</span><br><span class="line-number">75</span><br><span class="line-number">76</span><br><span class="line-number">77</span><br><span class="line-number">78</span><br><span class="line-number">79</span><br><span class="line-number">80</span><br><span class="line-number">81</span><br><span class="line-number">82</span><br><span class="line-number">83</span><br><span class="line-number">84</span><br><span class="line-number">85</span><br><span class="line-number">86</span><br><span class="line-number">87</span><br><span class="line-number">88</span><br><span class="line-number">89</span><br><span class="line-number">90</span><br><span class="line-number">91</span><br><span class="line-number">92</span><br><span class="line-number">93</span><br><span class="line-number">94</span><br><span class="line-number">95</span><br><span class="line-number">96</span><br><span class="line-number">97</span><br><span class="line-number">98</span><br><span class="line-number">99</span><br><span class="line-number">100</span><br><span class="line-number">101</span><br><span class="line-number">102</span><br><span class="line-number">103</span><br><span class="line-number">104</span><br><span class="line-number">105</span><br><span class="line-number">106</span><br><span class="line-number">107</span><br><span class="line-number">108</span><br><span class="line-number">109</span><br><span class="line-number">110</span><br><span class="line-number">111</span><br><span class="line-number">112</span><br><span class="line-number">113</span><br><span class="line-number">114</span><br><span class="line-number">115</span><br><span class="line-number">116</span><br><span class="line-number">117</span><br><span class="line-number">118</span><br><span class="line-number">119</span><br><span class="line-number">120</span><br><span class="line-number">121</span><br><span class="line-number">122</span><br><span class="line-number">123</span><br><span class="line-number">124</span><br><span class="line-number">125</span><br><span class="line-number">126</span><br></div></div><blockquote><p>文件存储服务工厂类</p></blockquote><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>import org.springframework.beans.factory.FactoryBean;\nimport org.springframework.beans.factory.annotation.Autowired;\nimport org.springframework.beans.factory.annotation.Value;\nimport org.springframework.beans.factory.config.AutowireCapableBeanFactory;\n\nimport java.util.HashMap;\nimport java.util.Map;\n\n/**\n * 文件存储服务工厂类\n * &lt;p&gt;Title: StorageFactory&lt;/p&gt;\n * &lt;p&gt;Description: &lt;/p&gt;\n *\n * @author Lusifer\n * @version 1.0.0\n * @date 2018/8/14 5:28\n */\npublic class StorageFactory implements FactoryBean&lt;StorageService&gt; {\n\n    @Autowired\n    private AutowireCapableBeanFactory acbf;\n\n    /**\n     * 存储服务的类型，目前仅支持fastdfs\n     */\n    @Value(&quot;${storage.type}&quot;)\n    private String type;\n\n    private Map&lt;String, Class&lt;? extends StorageService&gt;&gt; classMap;\n\n    public StorageFactory() {\n        classMap = new HashMap&lt;&gt;();\n        classMap.put(&quot;fastdfs&quot;, FastDFSStorageService.class);\n    }\n\n    @Override\n    public StorageService getObject() throws Exception {\n        Class&lt;? extends StorageService&gt; clazz = classMap.get(type);\n        if (clazz == null) {\n            throw new RuntimeException(&quot;Unsupported storage type [&quot; + type + &quot;], valid are &quot; + classMap.keySet());\n        }\n\n        StorageService bean = clazz.newInstance();\n        acbf.autowireBean(bean);\n        acbf.initializeBean(bean, bean.getClass().getSimpleName());\n        return bean;\n    }\n\n    @Override\n    public Class&lt;?&gt; getObjectType() {\n        return StorageService.class;\n    }\n\n    @Override\n    public boolean isSingleton() {\n        return true;\n    }\n}\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br><span class="line-number">47</span><br><span class="line-number">48</span><br><span class="line-number">49</span><br><span class="line-number">50</span><br><span class="line-number">51</span><br><span class="line-number">52</span><br><span class="line-number">53</span><br><span class="line-number">54</span><br><span class="line-number">55</span><br><span class="line-number">56</span><br><span class="line-number">57</span><br><span class="line-number">58</span><br></div></div><blockquote><p>配置文件存储服务工厂类</p></blockquote><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>import org.springframework.context.annotation.Bean;\nimport org.springframework.context.annotation.Configuration;\n\n/**\n * Java 配置方式定义 StorageFactory 的 Bean 使其可以被依赖注入\n * &lt;p&gt;Title: FastDFSConfiguration&lt;/p&gt;\n * &lt;p&gt;Description: &lt;/p&gt;\n *\n * @author Lusifer\n * @version 1.0.0\n * @date 2018/8/14 5:28\n */\n@Configuration\npublic class FastDFSConfiguration {\n    @Bean\n    public StorageFactory storageFactory() {\n        return new StorageFactory();\n    }\n}\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><blockquote><p>创建 FastDFS 控制器</p></blockquote><ol><li>增加云配置</li></ol><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>fastdfs.base.url: http://192.168.75.128:8888/\nstorage:\n  type: fastdfs\n  fastdfs:\n    tracker_server: 192.168.75.128:22122\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ol start="2"><li>控制器代码</li></ol><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>import com.funtl.itoken.service.upload.fastdfs.StorageService;\nimport org.springframework.beans.factory.annotation.Autowired;\nimport org.springframework.beans.factory.annotation.Value;\nimport org.springframework.web.bind.annotation.CrossOrigin;\nimport org.springframework.web.bind.annotation.RequestMapping;\nimport org.springframework.web.bind.annotation.RequestMethod;\nimport org.springframework.web.bind.annotation.RestController;\nimport org.springframework.web.multipart.MultipartFile;\n\nimport java.io.IOException;\nimport java.util.ArrayList;\nimport java.util.HashMap;\nimport java.util.List;\nimport java.util.Map;\n\n@CrossOrigin(origins = &quot;*&quot;, maxAge = 3600)\n@RestController\npublic class UploadController {\n    @Value(&quot;${fastdfs.base.url}&quot;)\n    private String FASTDFS_BASE_URL;\n\n    @Autowired\n    private StorageService storageService;\n\n    /**\n     * 文件上传\n     *\n     * @param dropFile    Dropzone\n     * @param editorFiles wangEditor\n     * @return\n     */\n    @RequestMapping(value = &quot;upload&quot;, method = RequestMethod.POST)\n    public Map&lt;String, Object&gt; upload(MultipartFile dropFile, MultipartFile[] editorFiles) {\n        Map&lt;String, Object&gt; result = new HashMap&lt;&gt;();\n\n        // Dropzone 上传\n        if (dropFile != null) {\n            result.put(&quot;fileName&quot;, writeFile(dropFile));\n        }\n\n        // wangEditor 上传\n        if (editorFiles != null &amp;&amp; editorFiles.length &gt; 0) {\n            List&lt;String&gt; fileNames = new ArrayList&lt;&gt;();\n\n            for (MultipartFile editorFile : editorFiles) {\n                fileNames.add(writeFile(editorFile));\n            }\n\n            result.put(&quot;errno&quot;, 0);\n            result.put(&quot;data&quot;, fileNames);\n        }\n\n        return result;\n    }\n\n    /**\n     * 将图片写入指定目录\n     *\n     * @param multipartFile\n     * @return 返回文件完整路径\n     */\n    private String writeFile(MultipartFile multipartFile) {\n        // 获取文件后缀\n        String oName = multipartFile.getOriginalFilename();\n        String extName = oName.substring(oName.lastIndexOf(&quot;.&quot;) + 1);\n\n        // 文件存放路径\n        String url = null;\n        try {\n            String uploadUrl = storageService.upload(multipartFile.getBytes(), extName);\n            url = FASTDFS_BASE_URL + uploadUrl;\n        } catch (IOException e) {\n            e.printStackTrace();\n        }\n\n        // 返回文件完整路径\n        return url;\n    }\n}\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br><span class="line-number">47</span><br><span class="line-number">48</span><br><span class="line-number">49</span><br><span class="line-number">50</span><br><span class="line-number">51</span><br><span class="line-number">52</span><br><span class="line-number">53</span><br><span class="line-number">54</span><br><span class="line-number">55</span><br><span class="line-number">56</span><br><span class="line-number">57</span><br><span class="line-number">58</span><br><span class="line-number">59</span><br><span class="line-number">60</span><br><span class="line-number">61</span><br><span class="line-number">62</span><br><span class="line-number">63</span><br><span class="line-number">64</span><br><span class="line-number">65</span><br><span class="line-number">66</span><br><span class="line-number">67</span><br><span class="line-number">68</span><br><span class="line-number">69</span><br><span class="line-number">70</span><br><span class="line-number">71</span><br><span class="line-number">72</span><br><span class="line-number">73</span><br><span class="line-number">74</span><br><span class="line-number">75</span><br><span class="line-number">76</span><br><span class="line-number">77</span><br><span class="line-number">78</span><br><span class="line-number">79</span><br></div></div>',23),r={render:function(n,s){return e}}}}]);